// Parse CS Insider Notion job board - v1.5: Fixed title parsing
const response = $input.first().json;

let html = response.content || '';
if (!html && typeof response === 'string') html = response;
if (!html) html = JSON.stringify(response);

const jobs = [];
const today = new Date().toISOString().split('T')[0];

console.log('HTML length:', html.length);

// Company extraction
const companyMatches = [];
const companyRegex = /Company<\/span>:?\s*([^<]+)/gi;
let match;
while ((match = companyRegex.exec(html)) !== null) {
  const company = match[1].trim();
  if (company.length > 1 && company.length < 100 && !companyMatches.includes(company)) {
    companyMatches.push(company);
  }
}

// Location extraction
const locationMatches = [];
const locationRegex = /Location<\/span>:?\s*([^<]+)/gi;
while ((match = locationRegex.exec(html)) !== null) {
  const loc = match[1].trim();
  if (loc.length > 1 && loc.length < 100 && !locationMatches.includes(loc)) {
    locationMatches.push(loc);
  }
}

// Apply links
const applyMatches = [];
const applyRegex = /href="(https:\/\/[^"]*(?:greenhouse|lever|workday|ashby|jobs\.|careers|apply|hiring)[^"]*)"/gi;
while ((match = applyRegex.exec(html)) !== null) {
  const url = match[1];
  if (!url.includes('notion.') && !url.includes('google.com') && !applyMatches.includes(url)) {
    applyMatches.push(url);
  }
}

// v1.5: Improved title extraction - filter out requirements
function isValidTitle(text) {
  // Skip if starts with colon or bullet
  if (/^[:\-\•\*]/.test(text)) return false;
  // Skip if contains "years" (requirement language)
  if (/\d+\+?\s*years?/i.test(text)) return false;
  // Skip if contains requirement words
  if (/\b(minimum|required|preferred|must have|experience in|proficiency|fluent|degree in)\b/i.test(text)) return false;
  // Skip if too long (requirements are usually verbose)
  if (text.length > 80) return false;
  // Must contain a role word
  if (!/\b(Manager|Director|Lead|Head|VP|Associate|Specialist|Coordinator|Partner|Executive)\b/i.test(text)) return false;
  return true;
}

const cleanTitles = [];
const titleRegex = />([^<]*(?:Customer Success|CSM|Client Success|Account Manager|Success Manager|Engagement Manager|Implementation|Onboarding)[^<]*)</gi;
while ((match = titleRegex.exec(html)) !== null) {
  const title = match[1].trim();
  if (title.length > 5 && isValidTitle(title) && !cleanTitles.includes(title)) {
    cleanTitles.push(title);
  }
}

console.log('Valid titles found:', cleanTitles.length, cleanTitles.slice(0, 5));

// Job ID helper
function extractJobId(url) {
  const patterns = [/\/jobs?\/([a-f0-9-]+)/i, /\/postings?\/([a-f0-9-]+)/i, /\/([0-9]+)(?:\?|$)/];
  for (const p of patterns) {
    const m = url.match(p);
    if (m) return m[1];
  }
  let hash = 0;
  for (let i = 0; i < url.length; i++) { hash = ((hash << 5) - hash) + url.charCodeAt(i); hash = hash & hash; }
  return 'csi-' + Math.abs(hash).toString(36);
}

// Build jobs - use default title if no valid title found
for (let i = 0; i < applyMatches.length; i++) {
  const company = companyMatches[i];
  const jobUrl = applyMatches[i];
  if (jobUrl && company) {
    jobs.push({
      json: {
        'Job Title': cleanTitles[i] || 'Customer Success Manager',
        'Company': company,
        'Location': locationMatches[i] || 'Remote',
        'Job URL': jobUrl,
        'Source': 'CS Insider',
        'Date Found': today,
        'Job ID': extractJobId(jobUrl)
      }
    });
  }
}

console.log('Jobs:', jobs.length, 'Companies:', companyMatches.length, 'URLs:', applyMatches.length);

if (jobs.length === 0) {
  return [{ json: { error: 'No jobs parsed', debug: { htmlLength: html.length, companies: companyMatches.slice(0,5), urls: applyMatches.slice(0,5), titles: cleanTitles.slice(0,5), htmlSample: html.substring(0, 2000) } } }];
}

return jobs;
